INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '装修虽老但仍然坚韧地想要散发出昔日辉煌的余晖，岭南风和经典港派中国风结合的没有违', '装修虽老但仍然坚韧地想要散发出昔日辉煌的余晖，岭南风和经典港派中国风结合的没有违和感，房间设施维护地尚可但卫生仍有提升空间，细节处把握不到位。酒店管理体现了国际化的水准，服务的标准化做得不错，对客人的需求响应比较积极。预定时提出了高楼层、无烟、远离电梯的要求，头晚的房间基本没达到这个要求，一夜因电梯噪音未休息好，看来酒店对客户的需求没有充分关注，管理在细节层面是存在疏漏和待改善之处。次日在夫人的反馈下，酒店更换调整了房间，说明酒店在回应客户需求和应急处理方面还是比较方面。酒店地理位置、设施配套、管理水准方面作为老牌五星还是具备一定的性价比的，没住过的可以感受一下。', '2024-10-04', 4, '[''房间设施'', ''安静程度'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234k12000fz1gu33F7D4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235q12000fz14pk19B21_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店高大上，房间干净整洁优雅，服务一流。花园设计漂亮心怡，有红色小桥，有大瀑布，', '酒店高大上，房间干净整洁优雅，服务一流。花园设计漂亮心怡，有红色小桥，有大瀑布，还有不同种的鱼游来游去，非常满意的一次住宿。', '2024-11-28', 5, '[''整体满意度'', ''卫生状况'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231e12000gx5i3vr2276_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230512000gx5mcsq7E23_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236c12000gx4t8997F0B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233512000gx5op6iF7F7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '订的红棉双床房，给升级了。酒店非常有历史，服务态度很好。大厅很气派，一家出行建议', '订的红棉双床房，给升级了。酒店非常有历史，服务态度很好。大厅很气派，一家出行建议订64平方米的，有两个洗脸台。设施不新了，房间窗户不能打开，一定要开空调换气。双床比较小，2人睡不开。可以不用订早餐，周边吃的很多。住置好，出行方便。', '2024-10-07', 4, '[''房间设施'', ''周边配套'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0230512000g0uctxqB4E6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233f12000g0tqd6697E1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235s12000g0u7fyq8F4F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '设施：这个房间标间我必需吐槽下，我性别女，是代父亲出门旅行，房间卫生间不封闭步入', '设施：这个房间标间我必需吐槽下，我性别女，是代父亲出门旅行，房间卫生间不封闭步入式浴缸外无遮挡，非常不方便。住三晚，第一晚结束问服务员，说标间都是这样，就没换房间，以后要是再代父亲出行，我可能不会选择这个酒店。自己来还会住。
服务：清洁很干净，头天叫送了一次矿泉水，第二天就自动多给了水，还主动送了糕点，体验感非常不错。服务员服务意识很强，态度也很好。
饮食：吃了荔湾亭早茶，算是规矩吧，之前在白天鹅吃了早茶，有了对比，比较的话性价比还行。', '2024-10-05', 3, '[''房间设施'', ''客房服务'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0230812000fzyz4tf171B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230x12000fzyp8lf386E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230r12000fzz8kc430F4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235n12000fzyqo606B8C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230z12000fzy7gzg9086_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232i12000fzz75ut1930_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '住了无数次，每次来广州都选这里，主要是周围太方便，吃喝玩乐哪哪都近，对面友谊商店', '住了无数次，每次来广州都选这里，主要是周围太方便，吃喝玩乐哪哪都近，对面友谊商店购物全满足，出门口就是地铁便宜的跑遍全广州，门口出租车24小时在线，市中心的地方到哪里哈皮都不怕的士费贵到哪里去。周围吃饭喝茶的地方打开大众点评全是各种老字号扎堆。有人说越秀区是广州的最中心，那花园酒店这里就是是越秀区的中心，非常喜欢这个位置，花园酒店的服务又代表了正宗老广的味道，所以，来广州就来试一试吧，门口的地铁还可以带你去好多地方畅游岭南文化', '2024-12-18', 5, '[''交通便利性'', ''周边配套'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234612000h9k33ea4683_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233u12000h9jshl36B22_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '地址位置优越，门口就是地铁，旁边广州酒家点都德非常方便', '地址位置优越，门口就是地铁，旁边广州酒家点都德非常方便', '2025-01-31', 5, '[''交通便利性'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0230f12000i77qwn8F37F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '每次出差广州，只要距离出差地点不太远，都会选择预订花园酒店，已经习惯了，各方面都', '每次出差广州，只要距离出差地点不太远，都会选择预订花园酒店，已经习惯了，各方面都还比较满意。
设施：满意
卫生：满意
环境：满意
服务：满意', '2024-11-15', 4, '[''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0234c12000gp1trqcD830_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236m12000gp2lupg27A2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236712000gp1mewd076D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '感谢工作人员YOLO，工作专业，给安排的房间非常好，酒店的庭院非常美，无论是石头', '感谢工作人员YOLO，工作专业，给安排的房间非常好，酒店的庭院非常美，无论是石头浮雕，还是瀑布，都意蕴着中华文化博大精深的浓厚底蕴，作为改革开放y的一面窗口，经典永远不会过时，给花园酒店点赞??另外，酒店地理位置优越，旁边就是地铁口，还有广州酒家、陶陶居等两家著名茶楼，推荐广州酒家炒面，陶陶居水牛奶蛋挞，期待下一次相遇。房间非常大，隔音，完全想不到有些人为啥要求那么苛刻。', '2024-10-04', 5, '[''整体满意度'', ''交通便利性'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0236912000fyupv9n1522_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230a12000fyufvsb150A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237112000fyukssbE5A6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233p12000fyudzz5BCF4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235912000fyub9fmE0C3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230x12000fytueor0ED9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230k12000fyurdzm4CC0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230b12000fyuivwl75EC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236712000fyubsqn79A0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州花园酒店名声在外慕名而来，后花园瀑布和锦鲤池让人赞叹不已，下午茶的点心名不虚', '广州花园酒店名声在外慕名而来，后花园瀑布和锦鲤池让人赞叹不已，下午茶的点心名不虚传，值得以后再来光顾～', '2025-03-15', 5, '[''公共设施'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230m12000j38dlr86EDA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234h12000j38fe8i4ACE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234p12000j36v4m5FD8F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '携程的3天2晚大床房套餐，看网上说大床房比较小，而且有施工噪音，在前台加钱升级的', '携程的3天2晚大床房套餐，看网上说大床房比较小，而且有施工噪音，在前台加钱升级的红棉房。
泳池很棒，在旁边躺着也很舒服。有毛巾和饮料。旁边有更衣室，桑拿，淋浴。
博物馆，值得参观下。了解酒店历史。
后花园有瀑布和鲤鱼池。在瀑布餐厅旁边的玻璃门出去，通道有点昏暗。出去后感觉进去另一个空间，但是旁边在施工，柴油味，打钻的声音，还有瀑布的隆隆水声，夹杂在一起，体验不是很好。
打卡酒店的瀑布餐厅(自助早餐)，桃圆餐厅(套餐形式的早餐)，30楼行政走廊(下午茶和晚上的欢乐时光)，还有荔湾厅。瀑布餐厅就是西式自助早餐，也有中式的早餐，面摊的细面好吃，但是没有粤式点心，图中的面包(展示柜里)不好吃。行政酒廊菜品太少，不建议去，但服务很到位，靠窗位只有早餐时间开放。荔湾厅吃了个粉，10%的服务费，不是很理解服务在哪里。本来还想去吃晚饭的，失望的不想去。
附近施工的噪音，房间也能听到，客房服务热心得给换了2次房间，但还是有噪音，不勉强，确实环境不允许。房间有些硬件不好，提了意见，酒店送了水果表示歉意，希望能改善吧。
整体体验可以，附近的施工结束后，会再去体验下。', '2024-09-02', 4, '[''安静程度'', ''房间设施'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0233i12000fcmutqt1F52_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234y12000fcne716DA53_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234212000fcn8dyhDA87_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233t12000fcmu9dtE667_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232012000fcn314zCF65_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233a12000fcn8cko83C9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233y12000fcmdll8121F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235312000fcnealwD4A3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231212000fcmpyha27CB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '很有南方风味的老字号酒店，时间长却不陈旧，服务贴心，善解人意，拥有了美好度假的时', '很有南方风味的老字号酒店，时间长却不陈旧，服务贴心，善解人意，拥有了美好度假的时光。', '2025-01-01', 5, '[''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232712000hj658g6B205_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常好的酒店，又免费升级了套房！交通方便！5号线地铁站在酒店门口，30层旋转餐厅', '非常好的酒店，又免费升级了套房！交通方便！5号线地铁站在酒店门口，30层旋转餐厅非常有特色，下次还会入住！', '2024-12-11', 5, '[''交通便利性'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236d12000h5iwzo1D97E_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0234p12000h5iwtfa2E92_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0231i12000h5iyz4iD0F6_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务特别好呀！Rem帅哥和李文美女姐姐服务都特别热情周到！下次来广州还会选择花园', '服务特别好呀！Rem帅哥和李文美女姐姐服务都特别热情周到！下次来广州还会选择花园酒店！餐食也特别好吃！', '2025-03-29', 5, '[''前台服务'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234v12000jeef6ff1249_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务除了前台偏冷漠外，其他都很好，早餐竹升面加牛腩很不错但一定要早点去，不然排队', '服务除了前台偏冷漠外，其他都很好，早餐竹升面加牛腩很不错但一定要早点去，不然排队很长，或者就是选酒廊早餐东西很少但胜在清净。受限于年代久远，房间设施有些古老了，很多开关设置不合理，顶高也有些压抑，但整体细节保养的不错，也有很多诸如化妆凳这样的贴心设置。室外的瀑布很有岭南风情，健身设施较全但有很多在维修。', '2024-10-06', 4, '[''房间设施'', ''餐饮设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0233r12000g07a6nm02D8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231t12000g077rvs659D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235s12000g06ox8wEB18_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间很舒适，服务很到位。瀑布花园很棒', '房间很舒适，服务很到位。瀑布花园很棒', '2025-02-17', 5, '[''整体满意度'', ''房间设施'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230g12000ikryiv8627B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '历史悠久 游玩内容丰富 吃喝玩乐一应俱全 还有博物馆。了老婆孩子都很开心。服务周', '历史悠久 游玩内容丰富 吃喝玩乐一应俱全 还有博物馆。了老婆孩子都很开心。服务周到 carrie还送我们一份行政酒廊小吃自助 体验很棒的旅途', '2024-11-10', 5, '[''整体满意度'', ''周边配套'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0237112000glp6zwr23DB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230k12000glp8m2k35F6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236w12000glpie92E68C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234l12000glppw4m4172_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236612000glpaj8m9D75_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/